const syncDuration = (startStr: string, endStr: string) => {
  if (!startStr || !endStr) return '';
  try {
    const [sh, sm] = startStr.split(':').map(Number);
    const [eh, em] = endStr.split(':').map(Number);
    const diffMinutes = eh * 60 + em - (sh * 60 + sm);
    return diffMinutes > 0 ? diffMinutes.toString() : '';
  } catch {
    return '';
  }
};

const syncEndTime = (startStr: string, durationStr: string) => {
  if (!startStr || !durationStr || isNaN(parseInt(durationStr))) return '';
  try {
    const [sh, sm] = startStr.split(':').map(Number);
    const totalMinutes = sh * 60 + sm + parseInt(durationStr || '0');
    const eh = Math.floor(totalMinutes / 60) % 24;
    const em = totalMinutes % 60;
    return `${eh.toString().padStart(2, '0')}:${em.toString().padStart(2, '0')}`;
  } catch {
    return '';
  }
};

const validate = (data = form) => {
  const errs: Record<string, string> = {};
  if (!data.date) errs.date = 'Vui lòng chọn ngày học.';

  if (!data.timeStart) errs.timeStart = 'Vui lòng nhập giờ bắt đầu.';
  if (!data.timeEnd) errs.timeEnd = 'Vui lòng nhập giờ kết thúc.';

  if (!data.duration.trim()) errs.duration = 'Vui lòng nhập thời lượng.';
  else if (isNaN(parseInt(data.duration)) || parseInt(data.duration) <= 0) {
    errs.duration = 'Thời lượng phải là số dương.';
  }

